"use client"

import Link from "next/link"
import { MessageCircle, Sparkles } from "lucide-react"
import { Card } from "@/components/ui/card"

interface Props {
  greeting: string
  userName: string
  agentName: string
  hasTelegramBound: boolean
  needsYouCount: number
  overnightClearedCount: number
  briefingChannels: string[]
}

function formatChannelList(channels: string[]): string {
  if (channels.length === 0) return ""
  if (channels.length === 1) return channels[0]
  if (channels.length === 2) return `${channels[0]} and ${channels[1]}`
  return `${channels.slice(0, -1).join(', ')}, and ${channels[channels.length - 1]}`
}

export default function ConciergeBriefing({
  greeting,
  userName,
  agentName,
  hasTelegramBound,
  needsYouCount,
  overnightClearedCount,
  briefingChannels,
}: Props) {
  const channelText = formatChannelList(briefingChannels)

  let narrative: React.ReactNode
  if (overnightClearedCount === 0 && needsYouCount === 0) {
    narrative = (
      <>You&apos;re all caught up — no new tickets since yesterday. I&apos;m on duty for anything that comes in.</>
    )
  } else if (overnightClearedCount === 0) {
    narrative = (
      <>
        Nothing new since yesterday, but{' '}
        <strong className="font-semibold text-foreground tabular-nums">{needsYouCount} ticket{needsYouCount === 1 ? '' : 's'}</strong>
        {' '}need{needsYouCount === 1 ? 's' : ''} your eye.
      </>
    )
  } else if (needsYouCount > 0) {
    narrative = (
      <>
        I drafted replies for{' '}
        <strong className="font-semibold text-foreground tabular-nums">{overnightClearedCount} ticket{overnightClearedCount === 1 ? '' : 's'}</strong>
        {channelText && <> across {channelText}</>}.
        {' '}
        <strong className="font-semibold text-foreground tabular-nums">{needsYouCount}</strong>
        {' '}still need{needsYouCount === 1 ? 's' : ''} your eye.
      </>
    )
  } else {
    narrative = (
      <>
        <strong className="font-semibold text-foreground tabular-nums">{overnightClearedCount} ticket{overnightClearedCount === 1 ? ' is' : 's are'}</strong>
        {' '}ready for you{channelText && <> from {channelText}</>}.
      </>
    )
  }

  return (
    <Card className="bg-card border-border rounded-2xl">
      <div className="flex items-start gap-3.5 px-6 pt-5 pb-5">
        <div className="size-9 rounded-full bg-primary text-primary-foreground flex items-center justify-center font-display-serif text-lg leading-none shrink-0 select-none" aria-hidden>
          {agentName.charAt(0).toUpperCase()}
        </div>

        <div className="min-w-0 flex-1">
          <p className="text-xs text-foreground/45 leading-none mt-1">
            <span className="font-semibold text-foreground/70">{agentName}</span> · briefing
          </p>
          <h1 className="mt-2.5 font-display-serif text-[27px] leading-tight text-foreground">
            {greeting}, <span className="italic text-[#9c9285]">{userName}</span>.
          </h1>
          <p className="mt-1.5 text-sm text-foreground/60 leading-relaxed max-w-2xl">
            {narrative}
          </p>

          <div className="flex items-center gap-2 mt-4 flex-wrap">
            {needsYouCount > 0 && (
              <a
                href="#needs-you"
                className="inline-flex items-center gap-1.5 px-4 py-1.5 rounded-full bg-amber-600 hover:bg-amber-700 text-primary-foreground text-xs font-semibold transition-colors"
              >
                Review {needsYouCount}
              </a>
            )}
            <Link
              href="/dashboard/tickets"
              className="px-4 py-1.5 rounded-full border border-border hover:bg-foreground/[0.04] text-xs font-semibold text-foreground/75 transition-colors"
            >
              Open inbox
            </Link>
            {hasTelegramBound ? (
              <Link
                href="/dashboard/integrations#telegram"
                className="inline-flex items-center gap-1.5 px-4 py-1.5 rounded-full bg-blue-600/10 hover:bg-blue-600/20 text-xs font-semibold text-blue-700 transition-colors"
              >
                <MessageCircle className="size-3" /> Message on Telegram
              </Link>
            ) : (
              <>
                <Link
                  href="/dashboard/integrations#telegram"
                  className="inline-flex items-center gap-1.5 px-4 py-1.5 rounded-full bg-blue-600/10 hover:bg-blue-600/20 text-xs font-semibold text-blue-700 transition-colors"
                >
                  <MessageCircle className="size-3" /> Connect Telegram
                </Link>
                <Link
                  href="/dashboard/agent"
                  className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-semibold text-foreground/55 hover:text-foreground/85 transition-colors"
                >
                  <Sparkles className="size-3" /> Open desk chat
                </Link>
              </>
            )}
          </div>
        </div>
      </div>
    </Card>
  )
}
